/// <summary>
/// extension class for class <c>CustVendSettle_cust</c>
/// </summary>
[ExtensionOf(Classstr(CustVendSettle_cust))]
internal final class ETGCustVendSettle_Cust_Extension
{
    public container con;
}

Method.Source:
public void updateTransOpen(CustVendTrans _custVendTrans, CustVendTransOpen _custVendTransOpen)
{
    next updateTransOpen( _custVendTrans,  _custVendTransOpen);

    //CS, DLT, 31012025, Customer and vendor payment journal integration with fusion
    if (this.moduleCustVend() == ModuleCustVend::Cust && BusinessEventsConfigurationReader::isBusinessEventEnabled(classStr(ETGCustPaymPostedBusinessEvent)))
    {
        CustTrans custTransETG;
        custTransETG = CustTrans::findByVoucher(_custVendTrans.Voucher);
        if (custTransETG && (custTransETG.TransType == LedgerTransType::Payment || custTransETG.TransType == LedgerTransType::None))
        {
            con +=[_custVendTrans.Voucher];
        }
    }
    //CE, DLT, 31012025, Customer and vendor payment journal integration with fusion
}

public void settleNow(dataAreaId _company, tableId _tableId, recId _recId, boolean _balancePostingProfile)
{
    next settleNow( _company,  _tableId,  _recId,  _balancePostingProfile);

    //CS, DLT, 31012025, Customer payment journal integration with fusion
    if (BusinessEventsConfigurationReader::isBusinessEventEnabled(classStr(ETGCustPaymPostedBusinessEvent)))
    {
        container cont = this.getVouchers();

        if(this.moduleCustVend() == ModuleCustVend::Cust)
        {
            ETGCustVendPaymSettlement::sendPaymentCust(cont);
        }
    }
    //CS, DLT, 31012025, Customer payment journal integration with fusion
}
